// Create canonical bridge key: smaller coord first
export function makeBridgeKey(island1, island2) {
  const x1 = island1.x, y1 = island1.y;
  const x2 = island2.x, y2 = island2.y;
  if (x1 < x2 || (x1 === x2 && y1 < y2)) {
    return `${x1},${y1},${x2},${y2}`;
  }
  return `${x2},${y2},${x1},${y1}`;
}

// Check if two islands are adjacent (same row/col, no island between)
export function areAdjacent(islands, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;
  if (from.x === to.x && from.y === to.y) return false;

  // Check no island between them
  for (const island of islands) {
    if (island.id === from.id || island.id === to.id) continue;
    if (from.x === to.x && island.x === from.x) {
      const minY = Math.min(from.y, to.y);
      const maxY = Math.max(from.y, to.y);
      if (island.y > minY && island.y < maxY) return false;
    }
    if (from.y === to.y && island.y === from.y) {
      const minX = Math.min(from.x, to.x);
      const maxX = Math.max(from.x, to.x);
      if (island.x > minX && island.x < maxX) return false;
    }
  }
  return true;
}

// Check if a bridge between two points would cross any existing bridge
export function wouldCross(islands, bridges, from, to) {
  const isHorizontal = from.y === to.y;

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);

    // Find the islands for this bridge
    const bridgeIsHorizontal = y1 === y2;

    // Only perpendicular bridges can cross
    if (isHorizontal === bridgeIsHorizontal) continue;

    if (isHorizontal) {
      // New bridge is horizontal (from.y === to.y), existing is vertical (x1===x2)
      const newMinX = Math.min(from.x, to.x);
      const newMaxX = Math.max(from.x, to.x);
      const newY = from.y;
      const existX = x1;
      const existMinY = Math.min(y1, y2);
      const existMaxY = Math.max(y1, y2);

      if (existX > newMinX && existX < newMaxX && newY > existMinY && newY < existMaxY) {
        return true;
      }
    } else {
      // New bridge is vertical (from.x === to.x), existing is horizontal (y1===y2)
      const newMinY = Math.min(from.y, to.y);
      const newMaxY = Math.max(from.y, to.y);
      const newX = from.x;
      const existY = y1;
      const existMinX = Math.min(x1, x2);
      const existMaxX = Math.max(x1, x2);

      if (newX > existMinX && newX < existMaxX && existY > newMinY && existY < newMaxY) {
        return true;
      }
    }
  }
  return false;
}

// Compute current bridge counts for each island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const island of islands) {
    counts.set(island.id, 0);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);

    for (const island of islands) {
      if ((island.x === x1 && island.y === y1) || (island.x === x2 && island.y === y2)) {
        counts.set(island.id, (counts.get(island.id) || 0) + count);
      }
    }
  }
  return counts;
}

// canAddBridge: check if adding delta bridges is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Check adjacency
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = makeBridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Check max 2
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing (only if adding new bridge where none existed)
  if (current === 0 && delta > 0) {
    if (wouldCross(islands, bridges, from, to)) {
      return { valid: false, error: "Bridges would cross" };
    }
  }

  return { valid: true, error: null };
}

// Check if all islands are connected
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;
  if (islands.length === 1) return true;

  // Build adjacency from bridges
  const adj = new Map();
  for (const island of islands) {
    adj.set(island.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);

    let id1 = null, id2 = null;
    for (const island of islands) {
      if (island.x === x1 && island.y === y1) id1 = island.id;
      if (island.x === x2 && island.y === y2) id2 = island.id;
    }

    if (id1 !== null && id2 !== null) {
      adj.get(id1).push(id2);
      adj.get(id2).push(id1);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const curr = queue.shift();
    for (const neighbor of (adj.get(curr) || [])) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check if puzzle is solved
export function isVictory(islands, bridges) {
  // Check all counts match
  const counts = computeCurrentCounts(islands, bridges);
  for (const island of islands) {
    if ((counts.get(island.id) || 0) !== island.value) return false;
  }

  // Check no crossings
  const bridgeList = [];
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    bridgeList.push(key);
  }

  for (let i = 0; i < bridgeList.length; i++) {
    const [x1, y1, x2, y2] = bridgeList[i].split(',').map(Number);
    const isH = y1 === y2;
    for (let j = i + 1; j < bridgeList.length; j++) {
      const [ax1, ay1, ax2, ay2] = bridgeList[j].split(',').map(Number);
      const isH2 = ay1 === ay2;
      if (isH === isH2) continue;

      if (isH) {
        const hMinX = Math.min(x1, x2), hMaxX = Math.max(x1, x2), hY = y1;
        const vX = ax1, vMinY = Math.min(ay1, ay2), vMaxY = Math.max(ay1, ay2);
        if (vX > hMinX && vX < hMaxX && hY > vMinY && hY < vMaxY) return false;
      } else {
        const hMinX = Math.min(ax1, ax2), hMaxX = Math.max(ax1, ax2), hY = ay1;
        const vX = x1, vMinY = Math.min(y1, y2), vMaxY = Math.max(y1, y2);
        if (vX > hMinX && vX < hMaxX && hY > vMinY && hY < vMaxY) return false;
      }
    }
  }

  // Check connectivity
  return checkConnectivity(islands, bridges);
}
LOGIC
